 1	import * as React from 'react';
 2	import { kialiStyle } from 'styles/StyleUtils';
 3	import { pluralize, Tooltip } from '@patternfly/react-core';
 4	
 5	import { JaegerTrace } from '../../types/TracingInfo';
 6	import { PFColors } from 'components/Pf/PfColors';
 7	import { FormattedTraceInfo, shortIDStyle } from './TracingResults/FormattedTraceInfo';
 8	
 9	interface Props {
10	  trace: JaegerTrace;
11	}
12	
13	const parentDivStyle = kialiStyle({
14	  fontSize: 'var(--graph-side-panel--font-size)',
15	  lineHeight: 1.3
16	});
17	
18	const nameStyle = kialiStyle({
19	  display: 'inline-block',
20	  maxWidth: 175,
21	  textOverflow: 'ellipsis',
22	  overflow: 'hidden',
23	  whiteSpace: 'nowrap'
24	});
25	
26	const errorStyle = kialiStyle({
27	  color: PFColors.Danger
28	});
29	
30	const secondaryLeftStyle = kialiStyle({
31	  color: PFColors.Color200
32	});
33	
34	const secondaryRightStyle = kialiStyle({
35	  color: PFColors.Color200,
36	  float: 'right'
37	});
38	
39	export const TraceListItem: React.FunctionComponent<Props> = props => {
40	  const formattedTrace = new FormattedTraceInfo(props.trace);
41	  const nameStyleToUse = formattedTrace.hasErrors() ? nameStyle + ' ' + errorStyle : nameStyle;
42	  return (
43	    <Tooltip
44	      content={
45	        <>
46	          {formattedTrace.name()}
47	          <span className={shortIDStyle}>{formattedTrace.shortID()}</span>
48	        </>
49	      }
50	    >
51	      <div className={parentDivStyle}>
52	        <span className={nameStyleToUse}>{formattedTrace.name()}</span>
53	        {formattedTrace.duration() ? <span className={secondaryRightStyle}>{formattedTrace.duration()}</span> : ''}
54	        <br />
55	        <span className={secondaryLeftStyle}>{pluralize(props.trace.spans.length, 'Span')}</span>
56	        <span className={secondaryRightStyle}>{formattedTrace.fromNow()}</span>
57	      </div>
58	    </Tooltip>
59	  );
60	};

